var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。`,ENG:`that you'll be with her, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called her to your office. She said she'd be here soon.`,TWN:`做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`LEEJIN_ALPHA_NULL_NULL`,text:{KOREA:`어머, 평소의 집무실과는 다르네요. 일하는 공간이 이렇게 요란해도 괜찮을까요?`,JPN:`あら、普段の社長室と雰囲気が違いますね。仕事場がこんなに派手でよろしいんですか？`,ENG:`Oh, your office looks different today. Are you sure you can focus on working while surrounded by all this razzmatazz?`,TWN:`哎呀，跟平時的辦公室不一樣呢。工作空間弄得這麼花俏沒關係嗎？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`LEEJIN_ALPHA_NULL_NULL`,text:{KOREA:`그리고 종신계약이라면......`,JPN:`それに終身契約は……`,ENG:`And about the lifetime contract,`,TWN:`然後終身契約……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`LEEJIN_ALPHA_NULL_NULL`,text:{KOREA:`매력 있는 제안은 아니네요. 예전부터 평생 고용이란 말에는 관심이 없었거든요.`,JPN:`魅力的な提案ではありませんね。以前から終身雇用に興味がありませんでしたので。`,ENG:`I can't say I'm interested. I've never been interested in being hired for life.`,TWN:`真是個沒有吸引力的提案呢。我從以前就對終生雇傭沒興趣。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`LEEJIN_ALPHA_NULL_NULL`,text:{KOREA:`그러니 이렇게 제안해 주시면 좋겠어요, 사장님.`,JPN:`ですから、提案の一部を修正していただきたいんです、社長。`,ENG:`So, why don't you rephrase your offer, Boss?`,TWN:`所以希望您可以這樣提案，老闆。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`LEEJIN_ALPHA_NULL_NULL`,text:{KOREA:`계약을 체결하면, 상사의 사랑을 한 몸에 받을 수 있다고 말이죠.`,JPN:`契約を結べば、上司の愛を一身に受けることができる、という内容を加えてほしいですね。`,ENG:`Perhaps you could say, "Sign the contract, and I'll spoil you with my love."`,TWN:`“願意簽訂契約的話，就可以獨佔老闆的愛了。”`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`LEEJIN_ALPHA_NULL_NULL`,text:{KOREA:`후훗, 그야 제 앞에 계신 분 얘기입니다만. 이런 말을 농담으로 꺼낼 만큼 입이 가볍지는 않아요.`,JPN:`ふふっ、もちろん私の目の前にいる方のことですよ。こんなこと、軽く冗談では言いません。`,ENG:`Hah hah. No, I'm not joking. I'm not so frivolous that I make a joke about something like that.`,TWN:`呵呵，不過這是在我前面的人該說的。我可沒有輕佻到會把這種話當玩笑講。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`LEEJIN_ALPHA_NULL_NULL`,text:{KOREA:`일 잘하는 비서가 필요하시다면, 기꺼이 힘을 빌려드리겠습니다.`,JPN:`優秀な秘書が必要でしたら、喜んでお力添えします。`,ENG:`If you need a competent secretary, look no further; I'm here for you.`,TWN:`如果您需要一個能幹的秘書，我非常樂意為您效力。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`LEEJIN_ALPHA_NULL_NULL`,text:{KOREA:`자, 그러니 제가 가르쳐드린대로, 다시 한 번 더 제안해 주시겠어요?`,JPN:`さぁ、私がお教えしたとおりに、もう一度提案していただけますか？`,ENG:`So, why don't you make me the offer once again?`,TWN:`那麼，您能按照我說的，重新提案一次嗎？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};